  // Lazy Steam App ID lookup — fires when a Questlog game opens with no confirmed Steam App ID.
  // Queries Steam storesearch AND IGDB in parallel; IGDB is the more reliable source since it
  // stores explicit Steam website links (category 13).
  useEffect(() => {
    if (!selectedGame || !('steam_url' in selectedGame)) return;
    const game = selectedGame as Game;
    if (/\/app\/\d+/.test(game.steam_url || '')) return; // already resolved
    if ((game as any)._steamLookupDone) return;
    fetch(`/api/resolve-steam?title=${encodeURIComponent(game.title)}`)
      .then(r => r.ok ? r.json() : null)
      .catch(() => null)
      .then(data => {
        const steamAppId = data?.steamAppId || null;
        if (steamAppId) {
          const newUrl = `https://store.steampowered.com/app/${steamAppId}/`;
          setSelectedGame(prev => prev ? { ...prev, steam_url: newUrl, _steamLookupDone: true } as any : prev);
          setGames(prev => prev.map(g => g.id === game.id ? { ...g, steam_url: newUrl } : g));
          fetch(`/api/games/${game.id}/steam-url`, {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
            body: JSON.stringify({ steam_url: newUrl })
          }).catch(() => {});
        } else {
          setSelectedGame(prev => prev ? { ...prev, _steamLookupDone: true } as any : prev);
        }
      });
  }, [(selectedGame as any)?.id]); // eslint-disable-line

  // Lazy Steam App ID lookup for external (Discover search) games that came from IGDB suggestions
