  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (!event.origin.endsWith('.run.app') && !event.origin.includes('localhost')) {
        return;
      }
      // Xbox auth messages are handled directly inside handleSyncXbox / handleSyncXboxFull
      // to avoid double-processing and stale alert() calls.
      if (event.data?.type ==='DISCORD_AUTH_SUCCESS') {
        setUser(prev => prev ? { ...prev, discord_id: event.data.discordId } : null);
        setSyncMessage({ title: 'Discord Connected', message: 'Your Discord account has been linked successfully.', type: 'success' });
        fetchHomeData();
      } else if (event.data?.type ==='DISCORD_AUTH_ERROR') {
        setSyncMessage({ title: 'Discord Connection Failed', message: event.data.error || 'Authentication failed. Please try again.', type: 'error' });
      }
    };

    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, []);

  const fetchHomeData = async () => {
    if (!token) return;
    setIsHomeLoading(true);
    try {
      const res = await fetch('/api/home/data', {
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setHomeData(data);
        // Sync full stats to remote (non-blocking)
        try {
          remoteSyncStats({
            library_count: data.stats?.libraryCount || 0,
            backlog_count: data.stats?.backlogCount || 0,
            total_playtime_hours: data.stats?.playtimeHours || 0,
            top_genre: data.stats?.topGenre || undefined,
            top_game: data.stats?.topGame || undefined,
          });
        } catch { /* non-critical */ }
        // Background pre-load metadata for unmatched Friends Activity games
        const unmatched = (data.friendsActivity || []).filter(
          (g: any) => !g.matchedLibraryId && !g.matchedQuestlogId
        );
        if (unmatched.length > 0) {
          (async () => {
            const { fetchGameInfo } = await import('./services/geminiService');
            for (const game of unmatched) {
              if (activityMetaCache.current.has(game.id)) continue;
              try {
                const info = await fetchGameInfo(game.title, game.steamAppID);
                activityMetaCache.current.set(game.id, { ...info, _cachedAt: Date.now() });
              } catch {}
              await new Promise(r => setTimeout(r, 600));
            }
            // Persist cache once after all fetches complete, not on every iteration
            try {
              const obj: any = {};
              activityMetaCache.current.forEach((v, k) => { obj[k] = v; });
              sessionStorage.setItem('ql_activity_meta', JSON.stringify(obj));
            } catch {}
          })();
        }
      }
    } catch (e) {
      console.error("Failed to fetch home data", e);
    } finally {
      setIsHomeLoading(false);
    }
  };

