  const handleSyncEpic = async () => {
    // If already linked, sync directly (server refreshes token automatically)
    if (user?.epic_account_id) {
      await doEpicSync(null);
      return;
    }
    // First time — use Electron IPC to open OAuth window and get auth code
    try {
      const ipcRenderer = (window as any).require?.('electron')?.ipcRenderer;
      if (!ipcRenderer) throw new Error('Epic OAuth requires the desktop app.');

      let code: string;
      try {
        code = await ipcRenderer.invoke('epic-oauth');
      } catch (e: any) {
        if (e.message?.includes('Auth window closed')) return; // user cancelled — silent
        throw e;
      }

      // Exchange code for tokens via server
      const exchRes = await fetch('/api/auth/epic/exchange', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify({ code }),
      });
      if (!exchRes.ok) {
        const d = await exchRes.json().catch(() => ({}));
        throw new Error(d.error || 'Token exchange failed');
      }
      const { accessToken, refreshToken, accountId } = await exchRes.json();

      // Store tokens
      await fetch('/api/launcher/link-epic', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify({ accessToken, refreshToken, accountId }),
      });
      setUser(prev => prev ? { ...prev, epic_account_id: accountId } : prev);
      await doEpicSync(accessToken);
    } catch (e: any) {
      setSyncMessage({ title: 'Epic Auth Failed', message: e.message || 'Authentication failed.', type: 'error' });
    }
  };

