  const handleLaunch = async (game: LauncherGame) => {
    try {
      await fetch('/api/launcher/launch', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify({ id: game.id })
      });

      if (game.platform === 'steam') {
        window.location.href = `steam://run/${game.external_id}`;
      } else if (game.platform === 'xbox') {
        const hexId = parseInt(game.external_id).toString(16).padStart(8, '0');
        openInBrowser(`ms-xbl-${hexId}://`);
        setActiveSession({ gameId: game.id, gameName: game.title, platform: 'xbox', sessionStart: Date.now() });
      } else if (game.platform === 'ea') {
        setActiveSession({ gameId: game.id, gameName: game.title, platform: 'ea', sessionStart: Date.now() });
      } else if (game.platform === 'local') {
        try {
          const { shell } = (window as any).require('electron');
          shell.openPath(game.launch_path);
        } catch {
          openInBrowser(`file://${game.launch_path}`);
        }
        setActiveSession({ gameId: game.id, gameName: game.title, platform: 'local', sessionStart: Date.now() });
      }

      setSelectedGame(null);
      fetchLauncherGames();
      fetchHomeData();
    } catch (e) {
      console.error(e);
    }
  };

